// Parse all 3 agent outputs
const base = $('Set — Normalize Input').item.json;

function safeParse(node) {
  try {
    const raw = $node[node].item.json;
    const content = raw.choices[0].message.content;
    return JSON.parse(content);
  } catch (e) {
    return {};
  }
}

const agent1 = safeParse('Agent 1 — Welcome Email Writer');
const agent2 = safeParse('Agent 2 — Onboarding Strategist');
const agent3 = safeParse('Agent 3 — Health Monitor');

// Build checklist text for email
const checklistHtml = (agent2.checklist || []).map(step => 
  `<li><strong>${step.task}</strong> — ${step.why_it_matters} <em>(~${step.time_estimate})</em></li>`
).join('');

// Enrich welcome email with checklist
const enrichedWelcomeHtml = (agent1.email_html || '') + 
  `<br><h3>Your Personalized Onboarding Checklist</h3><ol>${checklistHtml}</ol>` +
  `<p><strong>Quick Win (5 min):</strong> ${agent2.quick_win || ''}</p>`;

// Slack message
const slackText = `*New Customer Onboarded* 🎉\n*Name:* ${base.customer_name}\n*Company:* ${base.company_name}\n*Plan:* ${base.plan}\n*Industry:* ${base.industry}\n*Use Case:* ${base.use_case}\n*Quick Win Assigned:* ${agent2.quick_win || 'N/A'}\n*14-Day Goal:* ${agent2.success_milestone || 'N/A'}\n*Health Risks:* ${(agent3.health_risk_factors || []).join(', ')}\n*Risk Agent Pre-armed:* Day 3 & Day 5 emails queued ✅`;

return [{
  json: {
    ...base,
    // Agent 1 outputs
    welcome_subject: agent1.subject || `Welcome to ${base.product_name}, ${base.customer_name}!`,
    welcome_email_html: enrichedWelcomeHtml,
    first_line: agent1.first_line || '',
    tone_used: agent1.tone_used || 'professional-warm',
    // Agent 2 outputs
    checklist: agent2.checklist || [],
    quick_win: agent2.quick_win || '',
    success_milestone: agent2.success_milestone || '',
    recommended_features: (agent2.recommended_features || []).join(', '),
    // Agent 3 outputs
    day3_subject: agent3.day3_subject || `How's it going, ${base.customer_name}?`,
    day3_email_html: agent3.day3_email_html || '',
    day3_question: agent3.day3_question || '',
    reengagement_subject: agent3.reengagement_subject || `We saved your spot, ${base.customer_name}`,
    reengagement_email_html: agent3.reengagement_email_html || '',
    health_risk_factors: (agent3.health_risk_factors || []).join(', '),
    // Meta
    slack_text: slackText
  }
}];
